void hTree(double x, double y, double length, int depth) {
    if (depth == 0) return;
    drawLine(x-length/2, y, x+length/2, y);
    drawLine(x-length/2, y-length/2, x-length/2, y+length/2);
    drawLine(x+length/2, y-length/2, x+length/2, y+length/2);
