def bezier_point(points, t):
    pts = points[:]
    n = len(pts)
    while n > 1:
        for i in range(n - 1):
            x = (1 - t) * pts[i][0] + t * pts[i+1][0]
            y = (1 - t) * pts[i][1] + t * pts[i+1][1]
            pts[i] = (x, y)
        n -= 1
    return pts[0]

pair<double,double> bezierPoint(vector<pair<double,double>>& pts, double t) {
    int n = pts.size();
    vector<pair<double,double>> cur = pts;
    while (n > 1) {
        for (int i = 0; i < n-1; i++) {
            cur[i].first = (1-t) * cur[i].first + t * cur[i+1].first;
            cur[i].second = (1-t) * cur[i].second + t * cur[i+1].second;
        }
        n--;
    }
    return cur[0];
}

public static double[] bezierPoint(int[][] points, double t) {
    int n = points.length;
    double[][] cur = new double[n][2];
    for (int i = 0; i < n; i++) { cur[i][0] = points[i][0]; cur[i][1] = points[i][1]; }
    while (n > 1) {
        for (int i = 0; i < n-1; i++) {
            cur[i][0] = (1-t) * cur[i][0] + t * cur[i+1][0];
            cur[i][1] = (1-t) * cur[i][1] + t * cur[i+1][1];
        }
        n--;
    }
    return cur[0];
}

