public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (true) {
            int L = sc.nextInt(), R = sc.nextInt(), C = sc.nextInt();
            if (L == 0 && R == 0 && C == 0) break;
            char[][][] grid = new char[L][R][C];
            int sl = 0, sr = 0, sc2 = 0;
            for (int l = 0; l < L; l++)
                for (int r = 0; r < R; r++) {
                    String line = sc.next();
                    for (int c = 0; c < C; c++) {
                        grid[l][r][c] = line.charAt(c);
                        if (grid[l][r][c] == 'S') { sl = l; sr = r; sc2 = c; }
                    }
                }
            int result = bfs(L, R, C, grid, sl, sr, sc2);
            if (result == -1) System.out.println("Trapped!");
            else System.out.println("Escaped in " + result + " minute(s).");
        }
    }
    static int bfs(int L, int R, int C, char[][][] grid, int sl, int sr, int sc) {
        Queue<int[]> q = new LinkedList<>();
        boolean[][][] visited = new boolean[L][R][C];
        q.offer(new int[]{sr, sc, sl, 0});
        visited[sl][sr][sc] = true;
        int[] dr = {0,0,0,0,1,-1};
        int[] dc = {0,0,1,-1,0,0};
        int[] dl = {1,-1,0,0,0,0};
        while (!q.isEmpty()) {
            int[] cur = q.poll();
            int r = cur[0], c = cur[1], l = cur[2], d = cur[3];
            if (grid[l][r][c] == 'E') return d;
            for (int i = 0; i < 6; i++) {
                int nr = r+dr[i], nc = c+dc[i], nl = l+dl[i];
                if (nl >= 0 && nl < L && nr >= 0 && nr < R && nc >= 0 && nc < C &&
                    !visited[nl][nr][nc] && grid[nl][nr][nc] != '#') {
                    visited[nl][nr][nc] = true;
                    q.offer(new int[]{nr, nc, nl, d+1});
                }
            }
        }
        return -1;
    }
}

function dungeonMaster(L, R, C, grid) {
    let sr = 0, sc = 0, sl = 0;
