        const [r, c, l, dist] = q.shift();
        if (grid[l][r][c] === 'E') return `Escaped in ${dist} minute(s).`;
        for (const [dr, dc, dl] of dirs) {
            const nr = r+dr, nc = c+dc, nl = l+dl;
            if (nl >= 0 && nl < L && nr >= 0 && nr < R && nc >= 0 && nc < C &&
                !visited[nl][nr][nc] && grid[nl][nr][nc] !== '#') {
                visited[nl][nr][nc] = true;
                q.push([nr, nc, nl, dist+1]);
